import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const p=JSON.parse('{"title":"签证办理指南","description":"各国签证办理基础知识、材料清单和申请流程","frontmatter":{"title":"签证办理指南","description":"各国签证办理基础知识、材料清单和申请流程"},"headers":[],"relativePath":"knowledge/visa/index.md","filePath":"knowledge/visa/index.md","lastUpdated":null}'),i={name:"knowledge/visa/index.md"};function n(d,a,l,s,c,h){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="签证办理指南" tabindex="-1">签证办理指南 <a class="header-anchor" href="#签证办理指南" aria-label="Permalink to &quot;签证办理指南&quot;">​</a></h1><h2 id="签证基础知识" tabindex="-1">签证基础知识 <a class="header-anchor" href="#签证基础知识" aria-label="Permalink to &quot;签证基础知识&quot;">​</a></h2><p>签证是一个国家准许外国公民入境的文件。不同国家的签证政策差异很大，了解基础知识是成功申请的第一步。</p><h2 id="各国签证类型" tabindex="-1">各国签证类型 <a class="header-anchor" href="#各国签证类型" aria-label="Permalink to &quot;各国签证类型&quot;">​</a></h2><p>常见的签证类型包括旅游签证、商务签证、学生签证和工作签证等。针对旅行者，最常用的是旅游签证（B1/B2或短期申根签证）。</p><h2 id="签证申请流程" tabindex="-1">签证申请流程 <a class="header-anchor" href="#签证申请流程" aria-label="Permalink to &quot;签证申请流程&quot;">​</a></h2><p>签证申请通常包括填写申请表、准备材料、递交申请和面试（部分国家）等步骤。每个环节都需要认真准备。</p>',7)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
